import React, { useState, useEffect } from 'react';
import RankingNavbar from '../components/RankingNavbar';
import './Rankings.css';

const Rankings = () => {
    const [activeCategory, setActiveCategory] = useState('teams');
    const [activeFormat, setActiveFormat] = useState('t20i');
    const [loading, setLoading] = useState(false);

    // Mock data for initial implementation
    const mockRankings = {
        teams: {
            t20i: [
                { rank: 1, name: 'India', rating: 265, points: 15400 },
                { rank: 2, name: 'Australia', rating: 258, points: 12300 },
                { rank: 3, name: 'England', rating: 252, points: 11200 },
                { rank: 4, name: 'South Africa', rating: 250, points: 10800 },
                { rank: 5, name: 'Pakistan', rating: 245, points: 13500 }
            ],
            odi: [
                { rank: 1, name: 'India', rating: 121, points: 5800 },
                { rank: 2, name: 'Australia', rating: 118, points: 5200 },
                { rank: 3, name: 'South Africa', rating: 110, points: 4800 },
                { rank: 4, name: 'Pakistan', rating: 109, points: 4500 },
                { rank: 5, name: 'New Zealand', rating: 102, points: 4100 }
            ],
            test: [
                { rank: 1, name: 'Australia', rating: 124, points: 3400 },
                { rank: 2, name: 'India', rating: 120, points: 3800 },
                { rank: 3, name: 'England', rating: 115, points: 4200 },
                { rank: 4, name: 'South Africa', rating: 103, points: 2800 },
                { rank: 5, name: 'New Zealand', rating: 96, points: 2500 }
            ]
        },
        batting: {
            t20i: [
                { rank: 1, name: 'Suryakumar Yadav', team: 'IND', rating: 861 },
                { rank: 2, name: 'Phil Salt', team: 'ENG', rating: 802 },
                { rank: 3, name: 'Babar Azam', team: 'PAK', rating: 764 },
                { rank: 4, name: 'Mohammad Rizwan', team: 'PAK', rating: 755 },
                { rank: 5, name: 'Jos Buttler', team: 'ENG', rating: 716 }
            ],
            odi: [
                { rank: 1, name: 'Babar Azam', team: 'PAK', rating: 824 },
                { rank: 2, name: 'Shubman Gill', team: 'IND', rating: 801 },
                { rank: 3, name: 'Virat Kohli', team: 'IND', rating: 768 },
                { rank: 4, name: 'Rohit Sharma', team: 'IND', rating: 746 },
                { rank: 5, name: 'David Warner', team: 'AUS', rating: 738 }
            ],
            test: [
                { rank: 1, name: 'Kane Williamson', team: 'NZ', rating: 859 },
                { rank: 2, name: 'Joe Root', team: 'ENG', rating: 824 },
                { rank: 3, name: 'Steve Smith', team: 'AUS', rating: 818 },
                { rank: 4, name: 'Daryl Mitchell', team: 'NZ', rating: 780 },
                { rank: 5, name: 'Babar Azam', team: 'PAK', rating: 768 }
            ]
        },
        bowling: {
            t20i: [
                { rank: 1, name: 'Adil Rashid', team: 'ENG', rating: 726 },
                { rank: 2, name: 'Wanindu Hasaranga', team: 'SL', rating: 687 },
                { rank: 3, name: 'Akeal Hosein', team: 'WI', rating: 664 },
                { rank: 4, name: 'Axar Patel', team: 'IND', rating: 660 },
                { rank: 5, name: 'Maheesh Theekshana', team: 'SL', rating: 658 }
            ],
            odi: [
                { rank: 1, name: 'Keshav Maharaj', team: 'SA', rating: 716 },
                { rank: 2, name: 'Josh Hazlewood', team: 'AUS', rating: 688 },
                { rank: 3, name: 'Adam Zampa', team: 'AUS', rating: 675 },
                { rank: 4, name: 'Mohammed Siraj', team: 'IND', rating: 670 },
                { rank: 5, name: 'Jasprit Bumrah', team: 'IND', rating: 665 }
            ],
            test: [
                { rank: 1, name: 'Ravichandran Ashwin', team: 'IND', rating: 870 },
                { rank: 2, name: 'Josh Hazlewood', team: 'AUS', rating: 847 },
                { rank: 3, name: 'Jasprit Bumrah', team: 'IND', rating: 847 },
                { rank: 4, name: 'Kagiso Rabada', team: 'SA', rating: 834 },
                { rank: 5, name: 'Pat Cummins', team: 'AUS', rating: 820 }
            ]
        },
        allrounder: {
            t20i: [
                { rank: 1, name: 'Hardik Pandya', team: 'IND', rating: 222 },
                { rank: 2, name: 'Wanindu Hasaranga', team: 'SL', rating: 216 },
                { rank: 3, name: 'Mohammad Nabi', team: 'AFG', rating: 213 },
                { rank: 4, name: 'Sikandar Raza', team: 'ZIM', rating: 210 },
                { rank: 5, name: 'Marcus Stoinis', team: 'AUS', rating: 204 }
            ],
            odi: [
                { rank: 1, name: 'Mohammad Nabi', team: 'AFG', rating: 320 },
                { rank: 2, name: 'Shakib Al Hasan', team: 'BAN', rating: 292 },
                { rank: 3, name: 'Sikandar Raza', team: 'ZIM', rating: 288 },
                { rank: 4, name: 'Rashid Khan', team: 'AFG', rating: 257 },
                { rank: 5, name: 'Assad Vala', team: 'PNG', rating: 248 }
            ],
            test: [
                { rank: 1, name: 'Ravindra Jadeja', team: 'IND', rating: 444 },
                { rank: 2, name: 'Ravichandran Ashwin', team: 'IND', rating: 322 },
                { rank: 3, name: 'Shakib Al Hasan', team: 'BAN', rating: 310 },
                { rank: 4, name: 'Joe Root', team: 'ENG', rating: 298 },
                { rank: 5, name: 'Jason Holder', team: 'WI', rating: 285 }
            ]
        }
    };

    const currentData = mockRankings[activeCategory][activeFormat];

    return (
        <div className="rankings-page">
            <RankingNavbar 
                activeCategory={activeCategory} 
                setActiveCategory={setActiveCategory}
                activeFormat={activeFormat}
                setActiveFormat={setActiveFormat}
            />

            <div className="rankings-content">
                <div className="rankings-header">
                    <h2>ICC {activeFormat.toUpperCase()} {activeCategory.replace(/^\w/, (c) => c.toUpperCase())} Rankings</h2>
                    <span className="last-updated">Last Updated: March 12, 2026</span>
                </div>

                <div className="rankings-table-container">
                    <table className="rankings-table">
                        <thead>
                            <tr>
                                <th className="rank-col">Rank</th>
                                <th>{activeCategory === 'teams' ? 'Team' : 'Player'}</th>
                                {activeCategory !== 'teams' && <th>Team</th>}
                                <th>Rating</th>
                                {activeCategory === 'teams' && <th>Points</th>}
                            </tr>
                        </thead>
                        <tbody>
                            {currentData.map((item) => (
                                <tr key={item.rank} className={item.rank <= 3 ? `top-rank rank-${item.rank}` : ''}>
                                    <td className="rank-col">
                                        <div className="rank-badge">{item.rank}</div>
                                    </td>
                                    <td className="name-col">
                                        <span className="main-name">{item.name}</span>
                                    </td>
                                    {activeCategory !== 'teams' && (
                                        <td className="team-col">
                                            <span className="team-tag">{item.team}</span>
                                        </td>
                                    )}
                                    <td className="rating-col">
                                        <span className="rating-value">{item.rating}</span>
                                    </td>
                                    {activeCategory === 'teams' && (
                                        <td className="points-col">
                                            <span className="points-value">{item.points.toLocaleString()}</span>
                                        </td>
                                    )}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>

                <div className="rankings-disclaimer">
                    <p>* These rankings are updated regularly based on international performance. Data shown is purely for demonstration of the new feature.</p>
                </div>
            </div>
        </div>
    );
};

export default Rankings;
